module register_32bit (reset_clk, rst, en, data_in, q);
   input reset_clk, rst, en;
   input [31:0] data_in;
   output reg [31:0] q;

   always @(posedge reset_clk) begin
      if (rst)
         q <= 32'b00000000000000000000000000000000;
      else if (en)
         q <= data_in;
   end
endmodule
